import React, { useState, useEffect } from 'react';

function TestimonialCarousel() {
  const testimonials = [
    {
      quote: 'Lumina Creative is amazing! They helped me elevate my artistic vision and achieve my goals.',
      author: 'John Doe',
    },
    {
      quote: 'I was blown away by the quality of work and the professionalism of the team at Lumina Creative.',
      author: 'Jane Doe',
    },
    {
      quote: 'Lumina Creative is the best design agency I have ever worked with. They truly understand my artistic vision.',
      author: 'Bob Smith',
    },
  ];

  const [currentTestimonial, setCurrentTestimonial] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentTestimonial((prev) => (prev + 1) % testimonials.length);
    }, 5000);

    return () => clearInterval(intervalId);
  }, [testimonials.length]);

  return (
    <div className="bg-white py-12 md:py-24 lg:py-36">
      <div className="container mx-auto flex flex-col items-center justify-center">
        <h2 className="text-2xl md:text-4xl lg:text-6xl font-bold text-zinc-900 mb-4 md:mb-8 lg:mb-12">What Our Clients Say</h2>
        <div className="flex flex-col items-center justify-center">
          <p className="text-sm md:text-lg lg:text-2xl text-zinc-500 mb-4 md:mb-8 lg:mb-12">{testimonials[currentTestimonial].quote}</p>
          <p className="text-sm md:text-lg lg:text-2xl text-zinc-500">{testimonials[currentTestimonial].author}</p>
        </div>
        <div className="flex justify-center mt-8 md:mt-12 lg:mt-16">
          {testimonials.map((_, index) => (
            <button
              key={index}
              className={`mx-2 md:mx-4 lg:mx-6 w-2 md:w-4 lg:w-6 h-2 md:h-4 lg:h-6 rounded-full ${currentTestimonial === index ? 'bg-zinc-900' : 'bg-zinc-300'}`}
              onClick={() => setCurrentTestimonial(index)}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

export default TestimonialCarousel;

